===<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Confirmar Canje</title>
<style>
body { font-family: 'Montserrat', sans-serif; text-align: center; padding: 20px; background: #f8fafc; color: #334155; display: flex; align-items: center; justify-content: center; height: 100vh; margin: 0; flex-direction: column }
.card { background: white; padding: 40px; border-radius: 20px; box-shadow: 0 10px 25px rgba(0,0,0,0.05); max-width: 400px; width: 100% }
.icon { font-size: 50px; margin-bottom: 15px }
h1 { margin: 0 0 10px; font-size: 22px }
p { margin: 5px 0; color: #64748b; font-size: 15px }
.code { font-size: 24px; font-weight: bold; color: #0f172a; margin: 20px 0; padding: 15px; background: #f1f5f9; border: 2px dashed #cbd5e1; border-radius: 10px }
.btn-confirm { display: inline-block; background-color: #16a34a; color: white; text-decoration: none; padding: 16px 32px; border-radius: 30px; font-weight: 600; font-size: 16px; margin-top: 20px; width: 100%; box-sizing: border-box; border: none; cursor: pointer; transition: background 0.3s }
.btn-confirm:hover { background-color: #15803d }
.btn-cancel { display: inline-block; background-color: transparent; color: #ef4444; text-decoration: none; padding: 12px; font-weight: 600; font-size: 14px; margin-top: 10px; border: none; cursor: pointer }
</style>
<script>
function cancelarCanje() {
    document.body.innerHTML = "<div class='card'><div class='icon'>✋</div><h1>Canje Cancelado</h1><p>No se ha redimido el cupón. Puedes cerrar esta pantalla de forma segura.</p></div>";
}
</script>
</head>
<body>
<div class="card">
<div class="icon">👋</div>
<h1>Validar Cupón</h1>
<p>Cupón <strong>{{ $node["Supabase: Buscar Cupón"].json.tipo }}</strong> encontrado y listo para usar.</p>
<div class="code">{{ $node["Webhook (Canje QR)"].json.query.code }}</div>
<form method="POST" action="./confirmar-canje">
<input type="hidden" name="id" value="{{ $node['Supabase: Buscar Cupón'].json.id }}">
<input type="hidden" name="codigo" value="{{ $node['Webhook (Canje QR)'].json.query.code }}">
<button type="submit" class="btn-confirm">✔ Confirmar y Canjear</button>
</form>
<button type="button" onclick="cancelarCanje()" class="btn-cancel">Cancelar y no canjear</button>
</div>
</body>
</html>
